SELECT SUM(file_size) AS total_file_size
FROM metric_files
WHERE metric_id = 1;

SELECT category_name
FROM metric_categories
WHERE category_id = 1;

SELECT AVG(carbon_emissions) AS average_carbon_emissions
FROM environmental_metrics
WHERE year = 1961;

SELECT AVG(number_of_earths) AS avg_number_of_earths
FROM environmental_metrics
WHERE year = 2020;

SELECT COUNT(*) AS record_count
FROM environmental_metrics
WHERE year = 1962;

SELECT country_name
FROM countries
WHERE subregion = (SELECT subregion_id FROM subregions WHERE subregion_name = 'Northern Africa');
